#!/usr/bin/env bash
set -euo pipefail
source "$(dirname "$0")/lib/common.sh"
serial=; while (($#)); do case "$1" in --serial) serial="${2:?}"; shift 2;; -h|--help) echo "usage: $0 --serial SERIAL"; exit 0;; *) archphene_die "unknown argument: $1";; esac; done; [[ -n "$serial" ]] || archphene_die '--serial is required'; archphene_init_adb "$serial"
package=org.archphene.bridgeprobe; safe="$(sed 's/[^A-Za-z0-9._-]/_/g' <<<"$serial")"; mkdir -p "$ARCHPHENE_ROOT/artifacts"; xml="$ARCHPHENE_ROOT/artifacts/arm64-physical-$safe.xml"; png="$ARCHPHENE_ROOT/artifacts/arm64-physical-$safe.png"; [[ "$(archphene_adb_run get-state 2>/dev/null || true)" == device ]] || archphene_die "$serial is not an authorized ADB device"; abis="$(archphene_adb_run shell getprop ro.product.cpu.abilist | tr -d '\r')"; [[ ",$abis," == *,arm64-v8a,* ]] || archphene_die "$serial is not ARM64: $abis"
archphene_adb_run shell am force-stop "$package"; archphene_adb_run shell am start -W -n "$package/.MainActivity" >/dev/null; ui=; for _ in {1..10}; do sleep 1; ui="$(archphene_capture_ui arm64-physical || true)"; [[ "$ui" == *'Native checks:'* ]] && break; [[ "$ui" == *'package="com.android.systemui"'* ]] && archphene_die "device screen is locked; unlock $serial"; done; [[ "$ui" == *'Native checks:'* ]] || archphene_die 'native check report did not become visible'; printf '%s' "$ui" >"$xml"
for expected in 'ABIs: [arm64-v8a' 'DocumentsProvider: PASS read/write' 'Arch Linux ARM glibc: PASS ARCHPHENE_GLIBC_PASS' 'uname.machine=aarch64' 'AF_UNIX socketpair=PASS' 'socket transfer=PASS' 'shared mmap=PASS' 'Wayland shim dlopen/exports=PASS'; do [[ "$ui" == *"$expected"* ]] || archphene_die "missing ARM64 probe result: $expected"; done
archphene_tap_ui_pattern "$ui" 'text="RUN BRIDGE CHECKS"' bridge-check; sleep 0.5; uid_line="$(archphene_adb_run shell cmd package list packages -U "$package" | tr -d '\r' | grep -E "^package:$package uid:[0-9]+$" | head -n1)"; [[ -n "$uid_line" ]] || archphene_die 'Android did not assign app UID'; pid="$(archphene_adb_run shell pidof "$package" | tr -d '\r')"; [[ -n "$pid" ]] || archphene_die 'probe process is not running'; context="$(archphene_adb_run shell ps -AZ | grep -E "[[:space:]]$package$" | head -n1)"; [[ "$context" == *u:r:untrusted_app* ]] || archphene_die "unexpected SELinux domain: $context"; archphene_adb_run shell input keyevent KEYCODE_HOME; archphene_adb_run shell am start -W -n "$package/.MainActivity" >/dev/null; sleep 0.5; archphene_adb_run shell screencap -p /sdcard/arm64-physical.png; archphene_adb_run pull /sdcard/arm64-physical.png "$png" >/dev/null; archphene_note "ARM64 physical-device bridge passed on $serial ($abis), $uid_line, pid=$pid. Evidence: $xml Screenshot: $png"
